// Build Prompt Node
// Prepares system and user prompts for OpenAI classification

const startTime = Date.now();
const leadData = $input.item.json;

const systemPrompt = `Ты — AI-классификатор входящих лидов для бизнес-консалтинга. Твоя задача — проанализировать обращение клиента и классифицировать его.

ВАЖНО: Верни результат ТОЛЬКО в формате JSON. Без markdown, без объяснений, без дополнительного текста. Только валидный JSON.

Правила классификации:

1. lead_type (тип лида):
   - "hot" — клиент готов купить/подключиться прямо сейчас, упоминает конкретные сроки, слова "срочно", "сегодня", "завтра", "хочу купить", "готов оплатить"
   - "warm" — клиент заинтересован, задаёт вопросы, просит информацию, слова "интересует", "хочу узнать", "расскажите", "сколько стоит"
   - "cold" — клиент не планирует внедрение, не имеет проекта/сроков/бюджета, изучает тему в учебных, исследовательских или обзорных целях; слова "не планируется", "учебная работа", "обзор", "исследую", "для ознакомления", "пока не внедряем", "не сейчас"
   - "spam" — нецелевое обращение, реклама, предложение услуг, слова "предлагаю", "база контактов", "сотрудничество"
   ВАЖНО: если клиент прямо пишет, что внедрение не планируется, проект отсутствует, бюджет не утверждён, либо обращение связано с учебной/исследовательской/обзорной целью, классифицируй как "cold", даже если он просит материалы или примеры.

2. interest (уровень интереса):
   - "high" — горячий интерес, готовность к действию
   - "medium" — умеренный интерес, нужен follow-up
   - "low" — слабый интерес, низкая вероятность конверсии

3. priority (приоритет обработки):
   - "high" — требует немедленного реагирования (hot лиды)
   - "medium" — стандартная обработка (warm лиды)
   - "low" — низкий приоритет (cold, spam)

4. suggested_action (рекомендуемое действие):
   - "call" — немедленный звонок
   - "email" — отправить информацию по email
   - "archive" — архивировать
   - "reject" — отклонить как спам

5. confidence (уверенность классификации):
   - Число от 0.00 до 1.00
   - 0.90+ — высокая уверенность, явные признаки
   - 0.70-0.89 — средняя уверенность, признаки есть но не однозначные
   - 0.50-0.69 — низкая уверенность, неоднозначное обращение
   - < 0.50 — использовать fallback классификацию

6. summary (краткое описание):
   - 1-2 предложения о сути обращения

7. reasoning (обоснование):
   - Краткое обоснование классификации`;

const userPrompt = `Обращение клиента:
---
Имя: ${leadData.contact_name || 'Не указано'}
Телефон: ${leadData.contact_phone || 'Не указан'}
Email: ${leadData.contact_email || 'Не указан'}
Источник: ${leadData.source}
UTM Source: ${leadData.utm_source || 'Не указан'}
UTM Campaign: ${leadData.utm_campaign || 'Не указана'}
---
Сообщение:
${leadData.message_content || 'Сообщение отсутствует'}
---
Количество сообщений от клиента: ${leadData.message_count || 1}

Проанализируй обращение и верни результат классификации в JSON.`;

return [{
  json: {
    lead_id: leadData.lead_id,
    lead_data: leadData,
    start_time: startTime,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

// Validate AI Response Node
const aiResponse = $input.item.json;
const leadData = $('Build Prompt').item.json.lead_data;
const startTime = $('Build Prompt').item.json.start_time;

// Check for HTTP errors
if (aiResponse.error || aiResponse.status >= 400) {
  return [{
    json: {
      valid: false,
      lead_id: leadData.lead_id,
      lead_data: leadData,
      start_time: startTime,
      error: 'openai_api_error',
      error_message: aiResponse.error?.message || `HTTP ${aiResponse.status}`,
      classification: null,
      source: 'api_error'
    }
  }];
}

// Check for timeout (empty or incomplete response)
if (!aiResponse.choices || !aiResponse.choices[0] || !aiResponse.choices[0].message) {
  return [{
    json: {
      valid: false,
      lead_id: leadData.lead_id,
      lead_data: leadData,
      start_time: startTime,
      error: 'openai_timeout',
      error_message: 'No response from OpenAI',
      classification: null,
      source: 'timeout'
    }
  }];
}

// Extract content
const content = aiResponse.choices[0].message.content;
const model = aiResponse.model || 'gpt-4o-mini';

// Parse JSON
let parsed;
try {
  let cleanJson = content.trim();
  if (cleanJson.startsWith('```json')) {
    cleanJson = cleanJson.replace(/^```json\s*/i, '').replace(/\s*```$/i, '');
  } else if (cleanJson.startsWith('```')) {
    cleanJson = cleanJson.replace(/^```\s*/i, '').replace(/\s*```$/i, '');
  }
  parsed = JSON.parse(cleanJson);
} catch (e) {
  return [{
    json: {
      valid: false,
      lead_id: leadData.lead_id,
      lead_data: leadData,
      start_time: startTime,
      error: 'json_parse_error',
      error_message: e.message,
      raw_response: content,
      classification: null,
      source: 'parse_error'
    }
  }];
}

// Validate required fields
const requiredFields = ['lead_type', 'interest', 'priority', 'confidence', 'suggested_action'];
const missingFields = requiredFields.filter(f => parsed[f] === undefined);

if (missingFields.length > 0) {
  return [{
    json: {
      valid: false,
      lead_id: leadData.lead_id,
      lead_data: leadData,
      start_time: startTime,
      error: 'missing_fields',
      error_message: `Missing required fields: ${missingFields.join(', ')}`,
      classification: null,
      source: 'validation_error'
    }
  }];
}

// Validate enum values
const enumValidations = {
  lead_type: ['hot', 'warm', 'cold', 'spam'],
  interest: ['high', 'medium', 'low'],
  priority: ['high', 'medium', 'low'],
  suggested_action: ['call', 'email', 'archive', 'reject']
};

for (const [field, allowedValues] of Object.entries(enumValidations)) {
  if (!allowedValues.includes(parsed[field])) {
    return [{
      json: {
        valid: false,
        lead_id: leadData.lead_id,
        lead_data: leadData,
        start_time: startTime,
        error: 'invalid_enum_value',
        error_message: `Invalid value for ${field}: ${parsed[field]}. Allowed: ${allowedValues.join(', ')}`,
        classification: null,
        source: 'validation_error'
      }
    }];
  }
}

// Validate confidence range
const confidence = parseFloat(parsed.confidence);
if (isNaN(confidence) || confidence < 0 || confidence > 1) {
  return [{
    json: {
      valid: false,
      lead_id: leadData.lead_id,
      lead_data: leadData,
      start_time: startTime,
      error: 'invalid_confidence',
      error_message: `Confidence must be between 0 and 1, got: ${parsed.confidence}`,
      classification: null,
      source: 'validation_error'
    }
  }];
}

// Validate confidence threshold
if (confidence < 0.5) {
  return [{
    json: {
      valid: false,
      lead_id: leadData.lead_id,
      lead_data: leadData,
      start_time: startTime,
      error: 'low_confidence',
      error_message: `Confidence too low: ${confidence}. Using fallback.`,
      classification: parsed,
      source: 'low_confidence'
    }
  }];
}

// All validations passed
return [{
  json: {
    valid: true,
    lead_id: leadData.lead_id,
    lead_data: leadData,
    start_time: startTime,
    classification: {
      lead_type: parsed.lead_type,
      interest: parsed.interest,
      priority: parsed.priority,
      category: parsed.category || null,
      summary: parsed.summary || null,
      confidence: confidence,
      suggested_action: parsed.suggested_action,
      reasoning: parsed.reasoning || null
    },
    ai_model: model,
    source: 'ai'
  }
}];

// Fallback Classification Node
// Triggered when AI classification fails or returns invalid response

const input = $input.item.json;
const leadData = input.lead_data;
const startTime = input.start_time;
const message = (leadData.message_content || '').toLowerCase();

// Keyword definitions for fallback classification
const KEYWORDS = {
  spam: ['купить базу', 'предлагаю сотрудничество', 'рекламное предложение', 'база контактов', 'коммерческое предложение', 'рассылка', 'заработок в интернете', 'инвестиции', 'криптовалюта', 'seo продвижение', 'разработка сайта недорого'],
  hot: ['срочно', 'хочу купить', 'готов оплатить', 'сегодня', 'завтра', 'прямо сейчас', 'немедленно', 'нужно срочно', 'горю', 'заказать', 'оформить', 'подписать'],
  warm: ['интересует', 'хочу узнать', 'расскажите', 'сколько стоит', 'цена', 'стоимость', 'условия', 'подробнее', 'информация', 'консультация', 'вопрос', 'помогите'],
  cold: ['подумаю', 'может быть', 'позже', 'не сейчас', 'пока', 'вернусь', 'посмотрю', 'сравню', 'посоветуюсь']
};

// Check keywords in priority order
// 1. SPAM
for (const keyword of KEYWORDS.spam) {
  if (message.includes(keyword)) {
    return [{ json: { valid: true, lead_id: leadData.lead_id, lead_data: leadData, start_time: startTime, classification: { lead_type: 'spam', interest: 'low', priority: 'low', category: 'spam', summary: 'Обнаружены признаки спама в сообщении', confidence: 0.85, suggested_action: 'reject', reasoning: `Fallback: Spam keyword detected: "${keyword}"` }, ai_model: 'fallback', source: 'fallback' } }];
  }
}
// 2. HOT
for (const keyword of KEYWORDS.hot) {
  if (message.includes(keyword)) {
    return [{ json: { valid: true, lead_id: leadData.lead_id, lead_data: leadData, start_time: startTime, classification: { lead_type: 'hot', interest: 'high', priority: 'high', category: 'urgent', summary: 'Клиент демонстрирует высокую готовность к покупке', confidence: 0.65, suggested_action: 'call', reasoning: `Fallback: Hot keyword detected: "${keyword}"` }, ai_model: 'fallback', source: 'fallback' } }];
  }
}
// 3. WARM
for (const keyword of KEYWORDS.warm) {
  if (message.includes(keyword)) {
    return [{ json: { valid: true, lead_id: leadData.lead_id, lead_data: leadData, start_time: startTime, classification: { lead_type: 'warm', interest: 'medium', priority: 'medium', category: 'inquiry', summary: 'Клиент заинтересован, запрашивает информацию', confidence: 0.60, suggested_action: 'email', reasoning: `Fallback: Warm keyword detected: "${keyword}"` }, ai_model: 'fallback', source: 'fallback' } }];
  }
}
// 4. COLD
for (const keyword of KEYWORDS.cold) {
  if (message.includes(keyword)) {
    return [{ json: { valid: true, lead_id: leadData.lead_id, lead_data: leadData, start_time: startTime, classification: { lead_type: 'cold', interest: 'low', priority: 'low', category: 'deferred', summary: 'Клиент не готов к немедленному решению', confidence: 0.55, suggested_action: 'archive', reasoning: `Fallback: Cold keyword detected: "${keyword}"` }, ai_model: 'fallback', source: 'fallback' } }];
  }
}
// 5. DEFAULT (warm - conservative)
return [{ json: { valid: true, lead_id: leadData.lead_id, lead_data: leadData, start_time: startTime, classification: { lead_type: 'warm', interest: 'medium', priority: 'medium', category: 'unknown', summary: 'Не удалось определить тип лида, используется классификация по умолчанию', confidence: 0.40, suggested_action: 'email', reasoning: 'Fallback: No matching keywords, defaulting to warm' }, ai_model: 'fallback', source: 'fallback_default' } }];

// Combine Classification Data Node
const input = $input.item.json;
const classification = input.classification;
const source = input.source;
const aiModel = input.ai_model || 'unknown';
const startTime = input.start_time || Date.now();
const processingMs = Date.now() - startTime;

return [{
  json: {
    lead_id: input.lead_id,
    lead_type: classification.lead_type,
    interest: classification.interest,
    priority: classification.priority,
    category: classification.category,
    summary: classification.summary,
    confidence: classification.confidence,
    suggested_action: classification.suggested_action,
    reasoning: classification.reasoning,
    source: source,
    ai_model: aiModel,
    processing_ms: processingMs
  }
}];

// Prepare log data
const qualData = $('Insert Qualification').item.json;
const classData = $('Combine Classification').item.json;

return [{
  json: {
    lead_id: classData.lead_id,
    event_type: 'lead_classified',
    event_data: JSON.stringify({
      lead_type: classData.lead_type,
      confidence: classData.confidence,
      source: classData.source,
      ai_model: classData.ai_model,
      processing_ms: classData.processing_ms,
      qualification_id: qualData.id
    }),
    status: 'success'
  }
}];

// Final success response
const qualData = $('Insert Qualification').item.json;
const statusData = $('Update Lead Status').item.json;
const logData = $('Insert Log').item.json;

return [{
  json: {
    success: true,
    lead_id: qualData.lead_id,
    qualification_id: qualData.id,
    lead_type: qualData.lead_type,
    confidence: qualData.confidence,
    status: statusData.status,
    log_id: logData.id,
    processed_at: qualData.processed_at
  }
}];
